import React, { useContext, useState, useEffect } from "react";
import { auth } from "../../firebase/firebase"; // Import your Firebase auth instance
import { onAuthStateChanged } from "firebase/auth"; // Firebase method to listen to auth state changes

const AuthContext = React.createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [currentUser, setCurrentUser] = useState(null);
  const [userLoggedIn, setUserLoggedIn] = useState(false);
  const [isEmailUser, setIsEmailUser] = useState(false);
  const [isEmailVerified, setIsEmailVerified] = useState(false); // New state for email verification status
  const [isGoogleUser, setIsGoogleUser] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, initializeUser);
    return unsubscribe;
  }, []);

  async function initializeUser(user) {
    if (user) {
      // Update user information
      setCurrentUser({ ...user });

      // Check if the provider is email and password login
      const isEmail = user.providerData.some(
        (provider) => provider.providerId === "password"
      );
      setIsEmailUser(isEmail);

      // Check if the email is verified (for email/password logins)
      if (isEmail) {
        setIsEmailVerified(user.emailVerified); // Set email verification status
      }

      // Check if the auth provider is Google (optional)
      // const isGoogle = user.providerData.some(
      //   (provider) => provider.providerId === GoogleAuthProvider.PROVIDER_ID
      // );
      // setIsGoogleUser(isGoogle);

      setUserLoggedIn(true);
    } else {
      // If user is not logged in, reset all state
      setCurrentUser(null);
      setUserLoggedIn(false);
      setIsEmailVerified(false);
    }

    setLoading(false);
  }

  const value = {
    userLoggedIn,
    isEmailUser,
    isEmailVerified, // New value to expose email verification status
    isGoogleUser,
    currentUser,
    setCurrentUser
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
}
